define i16 @sext_shl_trunc_same_size(i16 %x, i32 %y) {
  %conv = sext i16 %x to i32
  %shl = shl i32 %conv, %y
  %t = trunc i32 %shl to i16
  ret i16 %t
}

define i32 @src_srem_shl_demand_eliminate_signbit(i32 %a0) {
  %srem = srem i32 %a0, 1073741824
  %shl = shl i32 %srem, 1
  %mask = and i32 %shl, 2
  ret i32 %mask
}

